import{_ as o,Z as a,P as s,g as n,k as l,m as t}from"./chunks/framework.Dp5g00Bf.js";const b=JSON.parse('{"title":"家庭组网攻略","description":"","frontmatter":{},"headers":[],"relativePath":"views/6-其他🧩/家庭组网攻略/index.md","filePath":"views/6-其他🧩/家庭组网攻略/index.md","lastUpdated":1778837408000}'),d={name:"views/6-其他🧩/家庭组网攻略/index.md"};function h(m,e,c,p,_,f){const i=a("NolebaseGitContributors"),r=a("NolebaseGitChangelog");return s(),n("div",{"data-pagefind-body":!0,"data-pagefind-meta":"date:1778837408000"},[e[0]||(e[0]=l('<h1 id="家庭组网攻略" tabindex="-1">家庭组网攻略 <a class="header-anchor" href="#家庭组网攻略" aria-label="Permalink to &quot;家庭组网攻略&quot;">​</a></h1><p>推荐直接使用同品牌支持mesh、支持最新wifi协议的路由器。mesh优先推荐使用有线mesh组网。如果没有预先布线，或者各个房间与弱电箱的网口是在无法打通的话，次推荐三频无线mesh路由器组网，但是这样的路由器价格更高，并且网速会有衰减，所以除非迫不得已，建议还是首选有线mesh。</p><h2 id="前期准备" tabindex="-1">前期准备 <a class="header-anchor" href="#前期准备" aria-label="Permalink to &quot;前期准备&quot;">​</a></h2><h5 id="一、确认网线面板里网线是否有接上" tabindex="-1">一、确认网线面板里网线是否有接上 <a class="header-anchor" href="#一、确认网线面板里网线是否有接上" aria-label="Permalink to &quot;一、确认网线面板里网线是否有接上&quot;">​</a></h5><p>首先把房间的网线盖板敲开，看看里面的网线是否有连接。对于老旧房屋还要注意里面的网线是4根还是8根的，如果4根的话那就只支持百兆了。网线如果没有连接需要自己根据盒子的上面的线序和颜色一根根接入。注意这里不同品牌的网线面板线序是不一样的，不要以为是通用的T568B，否则你直接不通。盖板的敲开方法很简单不用怕麻烦，小螺丝刀直接从底部的开孔那里直接撬。</p><h5 id="二、准备压线钳、水晶头、拨线环刀" tabindex="-1">二、准备压线钳、水晶头、拨线环刀 <a class="header-anchor" href="#二、准备压线钳、水晶头、拨线环刀" aria-label="Permalink to &quot;二、准备压线钳、水晶头、拨线环刀&quot;">​</a></h5><p>弱电箱里的线一般都是没有水晶头的，准备压线钳和水晶头后，便可以自己压线。 线序建议T568B(白橙、橙、白绿、蓝、白蓝、绿、白棕、粽)。其实有规律的，每一根双色线都会间隔一根纯色线。 <img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260510155916765.avif" alt=""></p><ol><li>使用拨弦环刀在大概3cm处把线皮拨开，一般转个两三圈就开了，注意不要伤到里面的线芯。</li><li>按照T568B的顺序从左往右进行理线，尽量把线缕直。之后先插入一下水晶头试一试是否差不多位置到位了。</li><li>使用网线钳剪掉大概1.5cm的线头，注意尽量剪的平齐。</li><li>将线头塞入到水晶头内，往前用力顶到位。</li><li>使用网线钳压住水晶头 线序一定要注意，是有触点的地方面对自己要符合T568B。 <img src="https://cdn.jsdelivr.net/gh/Ruin-L/image/img/20260510154052271.avif" alt=""></li></ol><h5 id="三、测试" tabindex="-1">三、测试 <a class="header-anchor" href="#三、测试" aria-label="Permalink to &quot;三、测试&quot;">​</a></h5><p>可以选择买线序仪进行测，也可以用笔记本电脑直连网线挨个测。如果绿灯和黄灯都在闪烁说明就是连上了。网速测试建议使用该网站(<a href="https://speedtest.im/" target="_blank" rel="noreferrer">https://speedtest.im/</a>)</p>',10)),t(i),t(r)])}const g=o(d,[["render",h]]);export{b as __pageData,g as default};
